module SIPO_Switch (  
    input clk,  
    input reset,  
    input serial_in,  
    output reg [4:0] parallel_out  
);  
    reg [4:0] unused_shift_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            unused_shift_reg <= 5'b00000;  
        end else begin  
            unused_shift_reg <= {unused_shift_reg[3:0], serial_in};  
        end  
    end  

    always @(*) begin  
        parallel_out = unused_shift_reg;  
    end  
endmodule
